292→    .argument("<input>", "Input video file or directory path")
293→    .option(
294→      "-m, --model <model>",
295→      "Model selection (pro, flash, flash-lite)",
296→      "pro"
297→    )
298→    .option(
299→      "-t, --tier <tier>",
