313→      "Number of screenshots to extract",
314→      "4"
315→    )
316→    .option(
317→      "-ac, --audio-chunk-minutes <number>",
318→      "Length of audio chunks in minutes",
319→      "10"
320→    )
321→    .option("-r, --report", "Generate a structured meeting report", false)
322→    .option(
323→      "-rd, --reports-dir <path>",
324→      "Custom directory for report output (defaults to input file location)"
325→    )
326→    .option(
327→      "-i, --instructions <text>",
328→      "Custom context or instructions to include in AI prompts"
329→    )
330→    .version(packageJson.version);
331→
332→  program.parse();
333→
334→  console.log(
335→    chalk.cyan(
336→      "⭐ Welcome to offmute - built by Hrishi (https://twitter.com/hrishioa) and named by Ben (https://twitter.com/bencmejla) ⭐"
337→    )
338→  );
339→
340→  const options = program.opts();
341→  const input = program.args[0];
342→
343→  // Handle model/tier selection with backward compatibility
344→  let modelOption: keyof typeof ALL_MODELS;
345→  if (options.tier) {
346→    console.log(chalk.yellow("Warning: --tier is deprecated. Please use --model instead."));
347→    modelOption = options.tier as keyof typeof ALL_MODELS;
348→  } else {
349→    modelOption = options.model as keyof typeof ALL_MODELS;
350→  }
351→
352→  if (!input || !ALL_MODELS[modelOption]) {
353→    console.error(chalk.red("Error: Invalid input path or model selection"));
354→    console.log(chalk.yellow("\nAvailable models:"));
355→    console.log(chalk.cyan("Simple model options:"));
356→    Object.entries(SIMPLE_MODELS).forEach(([key, value]) => {
357→      console.log(chalk.cyan(`- ${key}: ${value.label}`));
358→    });
359→    console.log(chalk.yellow("\nLegacy tier options (deprecated):"));
360→    Object.entries(MODEL_TIERS).forEach(([key, value]) => {
361→      console.log(chalk.gray(`- ${key}: ${value.label}`));
362→    });
363→    process.exit(1);
364→  }
365→
366→  // Create intermediates directory if specified
367→  if (options.intermediatesDir) {
368→    fs.mkdirSync(options.intermediatesDir, { recursive: true });
369→  }
370→
371→  // Create reports directory if specified
372→  if (options.reportsDir) {
373→    fs.mkdirSync(options.reportsDir, { recursive: true });
374→  }
375→
376→  const stats = fs.statSync(input);
377→  const files = stats.isDirectory() ? await findFiles(input) : [input];
378→
379→  if (files.length === 0) {
380→    console.error(chalk.red("No video files found"));
381→    process.exit(1);
382→  }
383→
384→console.log(
385→  chalk.green(
386→    ((audioCount: number) => {
387→      const videoCount = files.length - audioCount;
388→      const messages: string[] = [];
389→
390→      if (audioCount > 0) {
391→        messages.push(`Found ${audioCount} audio file${audioCount > 1 ? "s" : ""} to process`);
392→      }
393→      if (videoCount > 0) {
394→        messages.push(`Found ${videoCount} video file${videoCount > 1 ? "s" : ""} to process`);
395→      }
396→
397→      return messages.join('\n');
398→    })(files.filter(fn => isAudioFile(fn)).length)
399→  )
400→);
401→
402→  const startTime = Date.now();
403→  const results = {
404→    success: 0,
405→    failed: 0,
406→    failedFiles: [] as string[],
407→  };
408→
409→  for (const file of files) {
410→    try {
411→      await processFile(
412→        file,
413→        modelOption,
414→        options.saveIntermediates,
415→        options.intermediatesDir || null,
416→        parseInt(options.screenshotCount),
417→        parseInt(options.audioChunkMinutes),
418→        options.report,
419→        options.reportsDir,
420→        options.instructions
421→      );
422→      results.success++;
423→    } catch (error) {
424→      results.failed++;
425→      results.failedFiles.push(file);
426→    }
427→  }
428→
429→  const totalTime = (Date.now() - startTime) / 1000;
430→
431→  console.log(chalk.cyan("\nProcessing Summary:"));
432→  console.log(chalk.white(`Total time: ${formatDuration(totalTime)}`));
433→  console.log(
434→    chalk.green(`Successfully processed: ${results.success}/${files.length}`)
435→  );
436→
437→  if (results.failed > 0) {
438→    console.log(chalk.red("\nFailed files:"));
439→    results.failedFiles.forEach((file) =>
440→      console.log(chalk.yellow(`- ${file}`))
441→    );
442→    process.exit(1);
443→  } else if (results.success > 0) {
444→    console.log(
445→      chalk.cyan(
446→        "\n🌟 If that worked, consider starring https://github.com/southbridgeai/offmute !"
447→      )
448→    );
449→    console.log(chalk.cyan("    https://github.com/southbridgeai/offmute"));
450→  }
451→}
452→
453→process.on("unhandledRejection", (error) => {
454→  console.error(chalk.red("Fatal Error:"), error);
455→  process.exit(1);
456→});
457→
458→run();
