  1→import ffmpeg from "fluent-ffmpeg";
  2→import * as fs from "fs";
  3→import * as path from "path";
  4→import * as os from "os";
  5→
  6→interface ChunkInfo {
  7→  path: string;
  8→  startTime: number;
  9→  endTime: number;
 10→  index: number;
 11→}
 12→
 13→interface ProcessingResult {
 14→  chunks: ChunkInfo[];
 15→  tagSample: string;
 16→  workingDirectory: string;
 17→}
 18→
 19→interface ProcessOptions {
 20→  chunkMinutes?: number; // Default: 10
 21→  overlapMinutes?: number; // Default: 1
 22→  tagMinutes?: number; // Default: 20
 23→  outputDir?: string; // Default: OS temp directory
 24→}
 25→
 26→export async function processAudioFile(
 27→  inputFile: string,
 28→  options: ProcessOptions = {}
 29→): Promise<ProcessingResult> {
 30→  // Set default options
 31→  const {
 32→    chunkMinutes = 10,
 33→    overlapMinutes = 1,
 34→    tagMinutes = 20,
 35→    outputDir = path.join(os.tmpdir(), `audio_processing_${Date.now()}`),
 36→  } = options;
 37→
 38→  // Create output directory if it doesn't exist
 39→  if (!fs.existsSync(outputDir)) {
 40→    fs.mkdirSync(outputDir, { recursive: true });
 41→  }
 42→
 43→  // Get duration of input file
 44→  const duration = await getFileDuration(inputFile);
 45→  const baseFileName = path.basename(inputFile, path.extname(inputFile));
 46→
 47→  // Create promises for all operations
 48→  const processingPromises: Promise<any>[] = [];
 49→  const chunks: ChunkInfo[] = [];
 50→
 51→  // Generate tag sample promise
 52→  const tagSamplePath = path.join(outputDir, `${baseFileName}_tag_sample.mp3`);
 53→  if (!fs.existsSync(tagSamplePath)) {
 54→    processingPromises.push(
 55→      createMp3Chunk(inputFile, tagSamplePath, 0, tagMinutes * 60)
 56→    );
 57→  }
 58→
 59→  // Calculate chunk boundaries
 60→  const chunkDuration = chunkMinutes * 60;
 61→  const overlapDuration = overlapMinutes * 60;
 62→  const totalChunks = Math.ceil(duration / (chunkDuration - overlapDuration));
 63→
 64→  // Generate chunk processing promises
 65→  for (let i = 0; i < totalChunks; i++) {
 66→    const startTime = i * (chunkDuration - overlapDuration);
 67→    const endTime = Math.min(startTime + chunkDuration, duration);
 68→    const chunkPath = path.join(outputDir, `${baseFileName}_chunk_${i}.mp3`);
 69→
 70→    // Only process if chunk doesn't exist
 71→    if (!fs.existsSync(chunkPath)) {
 72→      processingPromises.push(
 73→        createMp3Chunk(inputFile, chunkPath, startTime, endTime)
 74→      );
 75→    }
 76→
 77→    chunks.push({
 78→      path: chunkPath,
 79→      startTime,
 80→      endTime,
 81→      index: i,
 82→    });
 83→  }
 84→
 85→  // Wait for all processing to complete
 86→  await Promise.all(processingPromises);
 87→
